    int threshold = Math.min(10, bufLength); // Check first 10 characters or less if buffer is smaller
    for (int i = 0; i < threshold; i++) {
        char c = charBuf[i];
        if (c == '\0') { // Null byte indicates binary content
            return true;
        }
        // Check for other indicators of binary data
        // Control characters (except common text ones like \t, \n, \r) can indicate binary
        if (c < 0x08 || (c > 0x0D && c < 0x20) || c == 0x7F) {
            return true;
        }
    }
    return false;
